/*@ Extern Coq (count_positive_spec : list Z -> Z) */
/*@ Import Coq Require Import count_positive */

int count_positive(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == count_positive_spec(l) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int cnt = 0;

    for (i = 0; i < n; ++i) {
        if (a[i] > 0) {
            cnt++;
        }
    }

    return cnt;
}

---V---
Require Import ZArith.
Require Import Coq.Lists.List.

Open Scope Z_scope.

Fixpoint count_positive_spec (l : list Z) : Z :=
  match l with
  | nil => 0
  | x :: xs =>
      (if Z_gt_dec x 0 then 1 else 0) + count_positive_spec xs
  end.

